xpath.script:
document.addEventListener('DOMContentLoaded', function () {
    var input = document.querySelector('input[name="add_qty"], #quantity');
    var errorBox = document.getElementById('price_break_min_qty_error');
    var minQty = ;
    var errorTimeout = null;

    function showError() {
        if (!errorBox || minQty <= 0) return;
        errorBox.style.display = 'block';
        clearTimeout(errorTimeout);
        errorTimeout = setTimeout(function () {
            errorBox.style.display = 'none';
        }, 4000);
    }

    function enforceMin() {
        if (!input || minQty <= 0) return;
        var val = parseFloat(input.value);
        if (isNaN(val) || val < minQty) {
            showError();
            input.value = minQty;
            ['input', 'change'].forEach(function(ev) {
                input.dispatchEvent(new Event(ev, { bubbles: true }));
            });
        }
    }

    if (input && minQty > 0) {
        // Valeur par défaut = quantité mini
        if (!input.value || parseFloat(input.value) < minQty) {
            input.value = minQty;
        }
        input.setAttribute('min', minQty);

        input.addEventListener('change', enforceMin);
        input.addEventListener('blur', enforceMin);

        // Surveillance des boutons +/- d'Odoo
        setInterval(function () {
            var val = parseFloat(input.value);
            if (!isNaN(val) && val < minQty) {
                enforceMin();
            }
        }, 300);
    }

    // --- Tableau des prix dégressifs ---
    var rows = document.querySelectorAll('.price-break-row');
    var lastValue = input ? input.value : '';

    function highlightMatchingRow(qty) {
        var matched = null;
        rows.forEach(function(row) {
            if (qty >= parseFloat(row.dataset.qty)) matched = row;
        });
        rows.forEach(function(r) { r.classList.remove('price-break-active'); });
        if (matched) matched.classList.add('price-break-active');
    }

    function updateHighlight() {
        if (input && input.value !== lastValue) {
            lastValue = input.value;
            var qty = parseFloat(input.value);
            if (!isNaN(qty)) highlightMatchingRow(qty);
        }
    }

    if (input) {
        input.addEventListener('input', updateHighlight);
        input.addEventListener('change', updateHighlight);
        setInterval(updateHighlight, 200);

        document.querySelectorAll('button, .btn, .fa-plus, .fa-minus, .btn-plus, .btn-minus').forEach(function(btn) {
            btn.addEventListener('click', function() { setTimeout(updateHighlight, 350); });
        });
    }

    rows.forEach(function(row) {
        row.addEventListener('click', function() {
            var qty = Math.max(parseFloat(row.dataset.qty), minQty || 0);
            if (input) {
                input.value = qty;
                lastValue = qty.toString();
                ['input', 'change', 'blur'].forEach(function(ev) {
                    input.dispatchEvent(new Event(ev, { bubbles: true }));
                });
            }
            highlightMatchingRow(qty);
        });
    });
});
